import{_ as e,o as n,c as t,a3 as i}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"219. Education And Training Royal Children S Hospital","description":"","frontmatter":{"title":"219. Education And Training Royal Children S Hospital","eba":"Mental Health Services 2024-2028","topics":["education-pd"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/education-pd/219-education-and-training-royal-children-s-hospital.md","filePath":"ebas/mental-health/management-admin/education-pd/219-education-and-training-royal-children-s-hospital.md"}'),o={name:"ebas/mental-health/management-admin/education-pd/219-education-and-training-royal-children-s-hospital.md"};function r(s,a,l,d,c,h){return n(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="_219-education-and-training-royal-children-s-hospital" tabindex="-1">219. Education And Training Royal Children S Hospital <a class="header-anchor" href="#_219-education-and-training-royal-children-s-hospital" aria-label="Permalink to &quot;219. Education And Training Royal Children S Hospital&quot;">​</a></h1><p>This clause only applies to Management and Administrative Officers at Royal Children’s Hospital classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement.</p><p><strong>219.1</strong> The parties recognise that the health services are regarded as state, national and international centres of excellence. As a consequence, the health services assume a vital role in education at a professional and community level.</p><p><strong>219.2</strong> The parties agree that Employees’ education will be supported on a formal and informal basis and that, wherever possible, resources will continue to be provided to support these programs.</p><p><strong>219.3</strong> Relevant and specific in-service education and training will be offered to all Employees on a regular basis comprising a minimum of four (4) hours per month.</p>',5)])])}const u=e(o,[["render",r]]);export{m as __pageData,u as default};
